          deep_dive: "Self-Consistency 实现：\ndef self_consistency(prompt, n=5):\n    responses = []\n    for _ in range(n):\n        resp = llm.generate(prompt + \" Let's think step by step.\")\n        answer = extract_final_answer(resp)  # 提取最终答案\n        responses.append(answer)\n    # 多数投票\n    from collections import Counter\n    return Counter(responses).most_common(1)[0][0]"
